  ('diplomatic-8a96f9fb-moex-00032', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-114-10317cea', 'sub-diplomatic-8a96f9fb-02', NULL, 'single_choice', '1949年四個日内瓦公約的共同第3條，確立在非國際性武裝衝突的情形下，衝突之各方對不實際 參與戰鬥人員應給予之人道待遇。下列何者非共同第3條具體提及之內容？', '["禁止劫持作為人質", "禁止強迫遷移", "禁止未經公正審判而判處刑罰", "公正的人道團體得向衝突各方提供服務的權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:49+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
