  ('diplomatic-8a96f9fb-moex-00035', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-114-e6f33b51', 'sub-diplomatic-8a96f9fb-03', NULL, 'essay', '區域貿易協定在世界貿易組織（World Trade Organization,WTO）杜哈
